const getUsersSummaryForAdmin = `-- name: GetUsersSummaryForAdmin :one
WITH filtered_users AS (
    SELECT
        id,
        cash_balance,
        grant_balance,
        status
    FROM users u
    WHERE
        (
            $1::text = ''
            OR u.email ILIKE '%' || $1::text || '%'
            OR COALESCE(u.nickname, '') ILIKE '%' || $1::text || '%'
        )
),
user_usage AS (
    SELECT
        user_id,
        COUNT(*)::bigint AS total_requests,
        (
            COALESCE(SUM(prompt_tokens), 0)::bigint +
            COALESCE(SUM(completion_tokens), 0)::bigint
        ) AS total_tokens
    FROM billing_logs
    WHERE user_id IN (SELECT id FROM filtered_users)
    GROUP BY user_id
),
active_keys AS (
    SELECT
        user_id,
        COUNT(*) FILTER (WHERE status = 1)::bigint AS active_key_count
    FROM api_keys
    WHERE user_id IN (SELECT id FROM filtered_users)
    GROUP BY user_id
)
SELECT
    COUNT(*)::bigint AS total_users,
    COUNT(*) FILTER (WHERE COALESCE(filtered_users.status, 0) = 1)::bigint AS active_users,
    COALESCE(SUM(filtered_users.cash_balance), 0)::bigint AS total_cash_balance,
    COALESCE(SUM(filtered_users.grant_balance), 0)::bigint AS total_grant_balance,
    COALESCE(SUM(COALESCE(user_usage.total_requests, 0)), 0)::bigint AS total_requests,
    COALESCE(SUM(COALESCE(user_usage.total_tokens, 0)), 0)::bigint AS total_tokens,
    COALESCE(SUM(COALESCE(active_keys.active_key_count, 0)), 0)::bigint AS total_active_keys
FROM filtered_users
LEFT JOIN user_usage ON user_usage.user_id = filtered_users.id
LEFT JOIN active_keys ON active_keys.user_id = filtered_users.id
`

type GetUsersSummaryForAdminRow struct {
	TotalUsers        int64
	ActiveUsers       int64
	TotalCashBalance  int64
	TotalGrantBalance int64
	TotalRequests     int64
	TotalTokens       int64
	TotalActiveKeys   int64
}

func (q *Queries) GetUsersSummaryForAdmin(ctx context.Context, keyword string) (GetUsersSummaryForAdminRow, error) {
	row := q.db.QueryRow(ctx, getUsersSummaryForAdmin, keyword)
	var i GetUsersSummaryForAdminRow
	err := row.Scan(
		&i.TotalUsers,
		&i.ActiveUsers,
		&i.TotalCashBalance,
		&i.TotalGrantBalance,
		&i.TotalRequests,
		&i.TotalTokens,
		&i.TotalActiveKeys,
	)
	return i, err
}

