const listUsersForAdmin = `-- name: ListUsersForAdmin :many
WITH user_usage AS (
    SELECT
        user_id,
        COUNT(*)::bigint AS total_requests,
        COALESCE(SUM(prompt_tokens), 0)::bigint AS total_prompt_tokens,
        COALESCE(SUM(completion_tokens), 0)::bigint AS total_completion_tokens,
        COALESCE(SUM(amount_cents), 0)::bigint AS total_amount_cents,
        MAX(created_at) AS last_request_at
    FROM billing_logs
    GROUP BY user_id
),
active_keys AS (
    SELECT
        user_id,
        COUNT(*) FILTER (WHERE status = 1)::bigint AS active_key_count
    FROM api_keys
    GROUP BY user_id
)
SELECT
    u.id,
    u.email,
    COALESCE(u.nickname, '') AS nickname,
    u.cash_balance,
    u.grant_balance,
    u.status,
    u.created_at,
    u.last_login_at,
    COALESCE(user_usage.total_requests, 0)::bigint AS total_requests,
    COALESCE(user_usage.total_prompt_tokens, 0)::bigint AS total_prompt_tokens,
    COALESCE(user_usage.total_completion_tokens, 0)::bigint AS total_completion_tokens,
    COALESCE(user_usage.total_amount_cents, 0)::bigint AS total_amount_cents,
    user_usage.last_request_at,
    COALESCE(active_keys.active_key_count, 0)::bigint AS active_key_count
FROM users u
LEFT JOIN user_usage ON user_usage.user_id = u.id
LEFT JOIN active_keys ON active_keys.user_id = u.id
WHERE
    (
        $1::text = ''
        OR u.email ILIKE '%' || $1::text || '%'
        OR COALESCE(u.nickname, '') ILIKE '%' || $1::text || '%'
    )
ORDER BY COALESCE(user_usage.last_request_at, u.created_at) DESC, u.id DESC
LIMIT $3
OFFSET $2
`

type ListUsersForAdminParams struct {
	Keyword   string
	OffsetVal int32
	LimitVal  int32
}

type ListUsersForAdminRow struct {
	ID                    int32
	Email                 string
	Nickname              string
	CashBalance           pgtype.Int8
	GrantBalance          pgtype.Int8
	Status                pgtype.Int4
	CreatedAt             pgtype.Timestamptz
	LastLoginAt           pgtype.Timestamptz
	TotalRequests         int64
	TotalPromptTokens     int64
	TotalCompletionTokens int64
	TotalAmountCents      int64
	LastRequestAt         interface{}
	ActiveKeyCount        int64
}

func (q *Queries) ListUsersForAdmin(ctx context.Context, arg ListUsersForAdminParams) ([]ListUsersForAdminRow, error) {
	rows, err := q.db.Query(ctx, listUsersForAdmin, arg.Keyword, arg.OffsetVal, arg.LimitVal)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListUsersForAdminRow
	for rows.Next() {
		var i ListUsersForAdminRow
		if err := rows.Scan(
			&i.ID,
			&i.Email,
			&i.Nickname,
			&i.CashBalance,
			&i.GrantBalance,
			&i.Status,
			&i.CreatedAt,
			&i.LastLoginAt,
			&i.TotalRequests,
			&i.TotalPromptTokens,
			&i.TotalCompletionTokens,
			&i.TotalAmountCents,
			&i.LastRequestAt,
			&i.ActiveKeyCount,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

